class Solution:
    def countMajoritySubarrays(self, nums, target):
        n = len(nums)
        pref = [0] * (n + 1)
        for i in range(n):
            pref[i + 1] = pref[i] + (1 if nums[i] == target else -1)
        ans = 0
        for j in range(n + 1):
            pj = pref[j]
            for i in range(j):
                if pref[i] < pj:
                    ans += 1
        return ans

