var countMajoritySubarrays = function(nums, target) {
    const n = nums.length;
    const offset = n + 1;
    const size = 2 * n + 3;
    const bit = new Array(size + 2).fill(0);
    const upd = (x) => {
        x += 1;
        while (x <= size) { bit[x] += 1; x += x & -x; }
    };
    const qry = (x) => {
        x += 1;
        let s = 0;
        while (x > 0) { s += bit[x]; x -= x & -x; }
        return s;
    };
    let ans = 0;
    let cur = 0;
    upd(cur + offset);
    for (let i = 0; i < n; i++) {
        cur += (nums[i] === target) ? 1 : -1;
        const v = cur + offset;
        ans += qry(v - 1);
        upd(v);
    }
    return ans;
};
